55	impl Completer for SlashCommandHelper {
56	    type Candidate = Pair;
57	
58	    fn complete(
59	        &self,
60	        line: &str,
61	        pos: usize,
62	        _ctx: &Context<'_>,
63	    ) -> rustyline::Result<(usize, Vec<Self::Candidate>)> {
64	        let Some(prefix) = slash_command_prefix(line, pos) else {
65	            return Ok((0, Vec::new()));
66	        };
67	
68	        let matches = self
69	            .completions
70	            .iter()
71	            .filter(|candidate| candidate.starts_with(prefix))
72	            .map(|candidate| Pair {
73	                display: candidate.clone(),
74	                replacement: candidate.clone(),
75	            })
76	            .collect();
77	
78	        Ok((0, matches))
79	    }
80	}
