106	impl LineEditor {
107	    #[must_use]
108	    pub fn new(prompt: impl Into<String>, completions: Vec<String>) -> Self {
109	        let config = Config::builder()
110	            .completion_type(CompletionType::List)
111	            .edit_mode(EditMode::Emacs)
112	            .build();
113	        let mut editor = Editor::<SlashCommandHelper, DefaultHistory>::with_config(config)
114	            .expect("rustyline editor should initialize");
115	        editor.set_helper(Some(SlashCommandHelper::new(completions)));
116	        editor.bind_sequence(KeyEvent(KeyCode::Char('J'), Modifiers::CTRL), Cmd::Newline);
117	        editor.bind_sequence(KeyEvent(KeyCode::Enter, Modifiers::SHIFT), Cmd::Newline);
118	
119	        Self {
120	            prompt: prompt.into(),
121	            editor,
122	        }
123	    }
124	
125	    pub fn push_history(&mut self, entry: impl Into<String>) {
126	        let entry = entry.into();
127	        if entry.trim().is_empty() {
128	            return;
129	        }
130	
131	        let _ = self.editor.add_history_entry(entry);
132	    }
133	
134	    pub fn set_completions(&mut self, completions: Vec<String>) {
135	        if let Some(helper) = self.editor.helper_mut() {
136	            helper.set_completions(completions);
137	        }
138	    }
139	
140	    pub fn read_line(&mut self) -> io::Result<ReadOutcome> {
141	        if !io::stdin().is_terminal() || !io::stdout().is_terminal() {
142	            return self.read_line_fallback();
143	        }
144	
145	        if let Some(helper) = self.editor.helper_mut() {
146	            helper.reset_current_line();
147	        }
148	
149	        match self.editor.readline(&self.prompt) {
150	            Ok(line) => Ok(ReadOutcome::Submit(line)),
151	            Err(ReadlineError::Interrupted) => {
152	                let has_input = !self.current_line().is_empty();
153	                self.finish_interrupted_read()?;
154	                if has_input {
155	                    Ok(ReadOutcome::Cancel)
156	                } else {
157	                    Ok(ReadOutcome::Exit)
158	                }
159	            }
160	            Err(ReadlineError::Eof) => {
161	                self.finish_interrupted_read()?;
162	                Ok(ReadOutcome::Exit)
163	            }
164	            Err(error) => Err(io::Error::other(error)),
165	        }
166	    }
167	
168	    fn current_line(&self) -> String {
169	        self.editor
170	            .helper()
171	            .map_or_else(String::new, SlashCommandHelper::current_line)
172	    }
173	
174	    fn finish_interrupted_read(&mut self) -> io::Result<()> {
175	        if let Some(helper) = self.editor.helper_mut() {
176	            helper.reset_current_line();
177	        }
178	        let mut stdout = io::stdout();
179	        writeln!(stdout)
180	    }
181	
182	    fn read_line_fallback(&self) -> io::Result<ReadOutcome> {
183	        let mut stdout = io::stdout();
184	        write!(stdout, "{}", self.prompt)?;
185	        stdout.flush()?;
186	
187	        let mut buffer = String::new();
188	        let bytes_read = io::stdin().read_line(&mut buffer)?;
189	        if bytes_read == 0 {
190	            return Ok(ReadOutcome::Exit);
191	        }
192	
193	        while matches!(buffer.chars().last(), Some('\n' | '\r')) {
194	            buffer.pop();
195	        }
196	        Ok(ReadOutcome::Submit(buffer))
197	    }
198	}
