200	fn slash_command_prefix(line: &str, pos: usize) -> Option<&str> {
201	    if pos != line.len() {
202	        return None;
203	    }
204	
205	    let prefix = &line[..pos];
206	    if !prefix.starts_with('/') {
207	        return None;
208	    }
209	
210	    Some(prefix)
211	}
