213	fn normalize_completions(completions: Vec<String>) -> Vec<String> {
214	    let mut seen = BTreeSet::new();
215	    completions
216	        .into_iter()
217	        .filter(|candidate| candidate.starts_with('/'))
218	        .filter(|candidate| seen.insert(candidate.clone()))
219	        .collect()
220	}
