25	impl SessionState {
26	    #[must_use]
27	    pub fn new(model: impl Into<String>) -> Self {
28	        Self {
29	            turns: 0,
30	            compacted_messages: 0,
31	            last_model: model.into(),
32	            last_usage: UsageSummary::default(),
