42	#[derive(Debug, Clone, PartialEq, Eq)]
43	pub enum SlashCommand {
44	    Help,
45	    Status,
46	    Compact,
47	    Model { model: Option<String> },
48	    Permissions { mode: Option<String> },
49	    Config { section: Option<String> },
50	    Memory,
51	    Clear { confirm: bool },
52	    Unknown(String),
53	}
54	
55	impl SlashCommand {
56	    #[must_use]
57	    pub fn parse(input: &str) -> Option<Self> {
58	        let trimmed = input.trim();
59	        if !trimmed.starts_with('/') {
60	            return None;
61	        }
62	
63	        let mut parts = trimmed.trim_start_matches('/').split_whitespace();
64	        let command = parts.next().unwrap_or_default();
65	        Some(match command {
66	            "help" => Self::Help,
67	            "status" => Self::Status,
68	            "compact" => Self::Compact,
69	            "model" => Self::Model {
70	                model: parts.next().map(ToOwned::to_owned),
71	            },
72	            "permissions" => Self::Permissions {
73	                mode: parts.next().map(ToOwned::to_owned),
74	            },
75	            "config" => Self::Config {
76	                section: parts.next().map(ToOwned::to_owned),
77	            },
78	            "memory" => Self::Memory,
79	            "clear" => Self::Clear {
80	                confirm: parts.next() == Some("--confirm"),
81	            },
82	            other => Self::Unknown(other.to_string()),
83	        })
84	    }
85	}
