87	struct SlashCommandHandler {
88	    command: SlashCommand,
89	    summary: &'static str,
90	}
91	
92	const SLASH_COMMAND_HANDLERS: &[SlashCommandHandler] = &[
93	    SlashCommandHandler {
94	        command: SlashCommand::Help,
95	        summary: "Show command help",
96	    },
97	    SlashCommandHandler {
98	        command: SlashCommand::Status,
99	        summary: "Show current session status",
100	    },
101	    SlashCommandHandler {
102	        command: SlashCommand::Compact,
103	        summary: "Compact local session history",
104	    },
105	    SlashCommandHandler {
106	        command: SlashCommand::Model { model: None },
107	        summary: "Show or switch the active model",
108	    },
109	    SlashCommandHandler {
110	        command: SlashCommand::Permissions { mode: None },
111	        summary: "Show or switch the active permission mode",
112	    },
113	    SlashCommandHandler {
114	        command: SlashCommand::Config { section: None },
115	        summary: "Inspect current config path or section",
116	    },
117	    SlashCommandHandler {
118	        command: SlashCommand::Memory,
119	        summary: "Inspect loaded memory/instruction files",
120	    },
121	    SlashCommandHandler {
122	        command: SlashCommand::Clear { confirm: false },
123	        summary: "Start a fresh local session",
124	    },
