135	impl CliApp {
136	    pub fn new(config: SessionConfig) -> Result<Self, RuntimeError> {
137	        let state = SessionState::new(config.model.clone());
138	        let conversation_client = ConversationClient::from_env(config.model.clone())?;
139	        Ok(Self {
140	            config,
141	            renderer: TerminalRenderer::new(),
142	            state,
143	            conversation_client,
144	            conversation_history: Vec::new(),
145	        })
146	    }
147	
148	    pub fn run_repl(&mut self) -> io::Result<()> {
149	        let mut editor = LineEditor::new("› ", Vec::new());
150	        println!("Rusty Claude CLI interactive mode");
151	        println!("Type /help for commands. Shift+Enter or Ctrl+J inserts a newline.");
152	
153	        loop {
154	            match editor.read_line()? {
155	                ReadOutcome::Submit(input) => {
156	                    if input.trim().is_empty() {
157	                        continue;
158	                    }
159	                    self.handle_submission(&input, &mut io::stdout())?;
160	                }
161	                ReadOutcome::Cancel => continue,
162	                ReadOutcome::Exit => break,
163	            }
164	        }
165	
166	        Ok(())
167	    }
168	
169	    pub fn run_prompt(&mut self, prompt: &str, out: &mut impl Write) -> io::Result<()> {
170	        self.render_response(prompt, out)
171	    }
172	
173	    pub fn handle_submission(
174	        &mut self,
175	        input: &str,
176	        out: &mut impl Write,
177	    ) -> io::Result<CommandResult> {
178	        if let Some(command) = SlashCommand::parse(input) {
179	            return self.dispatch_slash_command(command, out);
180	        }
181	
182	        self.state.turns += 1;
183	        self.render_response(input, out)?;
184	        Ok(CommandResult::Continue)
185	    }
186	
187	    fn dispatch_slash_command(
188	        &mut self,
189	        command: SlashCommand,
190	        out: &mut impl Write,
191	    ) -> io::Result<CommandResult> {
192	        match command {
193	            SlashCommand::Help => Self::handle_help(out),
194	            SlashCommand::Status => self.handle_status(out),
195	            SlashCommand::Compact => self.handle_compact(out),
196	            SlashCommand::Model { model } => self.handle_model(model.as_deref(), out),
197	            SlashCommand::Permissions { mode } => self.handle_permissions(mode.as_deref(), out),
198	            SlashCommand::Config { section } => self.handle_config(section.as_deref(), out),
199	            SlashCommand::Memory => self.handle_memory(out),
200	            SlashCommand::Clear { confirm } => self.handle_clear(confirm, out),
201	            SlashCommand::Unknown(name) => {
202	                writeln!(out, "Unknown slash command: /{name}")?;
203	                Ok(CommandResult::Continue)
204	            }
205	        }
206	    }
207	
208	    fn handle_help(out: &mut impl Write) -> io::Result<CommandResult> {
209	        writeln!(out, "Available commands:")?;
210	        for handler in SLASH_COMMAND_HANDLERS {
211	            let name = match handler.command {
212	                SlashCommand::Help => "/help",
213	                SlashCommand::Status => "/status",
214	                SlashCommand::Compact => "/compact",
215	                SlashCommand::Model { .. } => "/model [model]",
216	                SlashCommand::Permissions { .. } => "/permissions [mode]",
217	                SlashCommand::Config { .. } => "/config [section]",
218	                SlashCommand::Memory => "/memory",
219	                SlashCommand::Clear { .. } => "/clear [--confirm]",
220	                SlashCommand::Unknown(_) => continue,
221	            };
222	            writeln!(out, "  {name:<9} {}", handler.summary)?;
223	        }
224	        Ok(CommandResult::Continue)
225	    }
226	
227	    fn handle_status(&mut self, out: &mut impl Write) -> io::Result<CommandResult> {
228	        writeln!(
229	            out,
230	            "status: turns={} model={} permission-mode={:?} output-format={:?} last-usage={} in/{} out config={}",
231	            self.state.turns,
232	            self.state.last_model,
233	            self.config.permission_mode,
234	            self.config.output_format,
235	            self.state.last_usage.input_tokens,
236	            self.state.last_usage.output_tokens,
237	            self.config
238	                .config
239	                .as_ref()
240	                .map_or_else(|| String::from("<none>"), |path| path.display().to_string())
241	        )?;
242	        Ok(CommandResult::Continue)
243	    }
244	
245	    fn handle_compact(&mut self, out: &mut impl Write) -> io::Result<CommandResult> {
246	        self.state.compacted_messages += self.state.turns;
247	        self.state.turns = 0;
