353	    fn handle_stream_event(
354	        renderer: &TerminalRenderer,
355	        event: StreamEvent,
356	        stream_spinner: &mut Spinner,
357	        tool_spinner: &mut Spinner,
358	        saw_text: &mut bool,
359	        turn_usage: &mut UsageSummary,
360	        out: &mut impl Write,
361	    ) {
362	        match event {
363	            StreamEvent::TextDelta(delta) => {
364	                if !*saw_text {
365	                    let _ =
366	                        stream_spinner.finish("Streaming response", renderer.color_theme(), out);
367	                    *saw_text = true;
368	                }
369	                let _ = write!(out, "{delta}");
370	                let _ = out.flush();
371	            }
372	            StreamEvent::ToolCallStart { name, input } => {
373	                if *saw_text {
374	                    let _ = writeln!(out);
375	                }
376	                let _ = tool_spinner.tick(
377	                    &format!("Running tool `{name}` with {input}"),
378	                    renderer.color_theme(),
379	                    out,
380	                );
381	            }
382	            StreamEvent::ToolCallResult {
383	                name,
384	                output,
385	                is_error,
386	            } => {
387	                let label = if is_error {
388	                    format!("Tool `{name}` failed")
389	                } else {
390	                    format!("Tool `{name}` completed")
391	                };
392	                let _ = tool_spinner.finish(&label, renderer.color_theme(), out);
393	                let rendered_output = format!("### Tool `{name}`\n\n```text\n{output}\n```\n");
394	                let _ = renderer.stream_markdown(&rendered_output, out);
395	            }
396	            StreamEvent::Usage(usage) => {
397	                *turn_usage = usage;
398	            }
399	        }
400	    }
401	
402	    fn write_turn_output(
403	        &self,
404	        summary: &runtime::TurnSummary,
405	        out: &mut impl Write,
406	    ) -> io::Result<()> {
407	        match self.config.output_format {
408	            OutputFormat::Text => {
409	                writeln!(
410	                    out,
411	                    "\nToken usage: {} input / {} output",
412	                    self.state.last_usage.input_tokens, self.state.last_usage.output_tokens
413	                )?;
414	            }
415	            OutputFormat::Json => {
416	                writeln!(
417	                    out,
418	                    "{}",
419	                    serde_json::json!({
420	                        "message": summary.assistant_text,
421	                        "usage": {
422	                            "input_tokens": self.state.last_usage.input_tokens,
423	                            "output_tokens": self.state.last_usage.output_tokens,
424	                        }
425	                    })
426	                )?;
427	            }
428	            OutputFormat::Ndjson => {
429	                writeln!(
430	                    out,
431	                    "{}",
432	                    serde_json::json!({
433	                        "type": "message",
434	                        "text": summary.assistant_text,
435	                        "usage": {
436	                            "input_tokens": self.state.last_usage.input_tokens,
437	                            "output_tokens": self.state.last_usage.output_tokens,
438	                        }
439	                    })
440	                )?;
441	            }
442	        }
443	        Ok(())
444	    }
445	
446	    fn render_response(&mut self, input: &str, out: &mut impl Write) -> io::Result<()> {
447	        let mut stream_spinner = Spinner::new();
448	        stream_spinner.tick(
449	            "Opening conversation stream",
450	            self.renderer.color_theme(),
451	            out,
452	        )?;
453	
454	        let mut turn_usage = UsageSummary::default();
455	        let mut tool_spinner = Spinner::new();
456	        let mut saw_text = false;
457	        let renderer = &self.renderer;
458	
459	        let result =
460	            self.conversation_client
461	                .run_turn(&mut self.conversation_history, input, |event| {
462	                    Self::handle_stream_event(
463	                        renderer,
464	                        event,
465	                        &mut stream_spinner,
466	                        &mut tool_spinner,
467	                        &mut saw_text,
468	                        &mut turn_usage,
469	                        out,
470	                    );
471	                });
472	
473	        let summary = match result {
474	            Ok(summary) => summary,
475	            Err(error) => {
476	                stream_spinner.fail(
477	                    "Streaming response failed",
478	                    self.renderer.color_theme(),
479	                    out,
480	                )?;
481	                return Err(io::Error::other(error));
482	            }
483	        };
484	        self.state.last_usage = summary.usage.clone();
485	        if saw_text {
486	            writeln!(out)?;
487	        } else {
488	            stream_spinner.finish("Streaming response", self.renderer.color_theme(), out)?;
489	        }
490	
491	        self.write_turn_output(&summary, out)?;
492	        let _ = turn_usage;
493	        Ok(())
494	    }
495	}
