170	impl RenderState {
171	    fn style_text(&self, text: &str, theme: &ColorTheme) -> String {
172	        let mut style = text.stylize();
173	
174	        if matches!(self.heading_level, Some(1 | 2)) || self.strong > 0 {
175	            style = style.bold();
176	        }
177	        if self.emphasis > 0 {
178	            style = style.italic();
179	        }
180	
181	        if let Some(level) = self.heading_level {
182	            style = match level {
183	                1 => style.with(theme.heading),
184	                2 => style.white(),
185	                3 => style.with(Color::Blue),
186	                _ => style.with(Color::Grey),
187	            };
188	        } else if self.strong > 0 {
189	            style = style.with(theme.strong);
190	        } else if self.emphasis > 0 {
191	            style = style.with(theme.emphasis);
192	        }
193	
194	        if self.quote > 0 {
195	            style = style.with(theme.quote);
196	        }
197	
198	        format!("{style}")
199	    }
