251	    pub fn render_markdown(&self, markdown: &str) -> String {
252	        let mut output = String::new();
253	        let mut state = RenderState::default();
254	        let mut code_language = String::new();
255	        let mut code_buffer = String::new();
256	        let mut in_code_block = false;
257	
258	        for event in Parser::new_ext(markdown, Options::all()) {
259	            self.render_event(
260	                event,
261	                &mut state,
262	                &mut output,
263	                &mut code_buffer,
