276	
277	    #[allow(clippy::too_many_lines)]
278	    fn render_event(
279	        &self,
280	        event: Event<'_>,
281	        state: &mut RenderState,
282	        output: &mut String,
283	        code_buffer: &mut String,
284	        code_language: &mut String,
285	        in_code_block: &mut bool,
286	    ) {
287	        match event {
288	            Event::Start(Tag::Heading { level, .. }) => {
289	                Self::start_heading(state, level as u8, output);
290	            }
291	            Event::End(TagEnd::Paragraph) => output.push_str("\n\n"),
292	            Event::Start(Tag::BlockQuote(..)) => self.start_quote(state, output),
293	            Event::End(TagEnd::BlockQuote(..)) => {
294	                state.quote = state.quote.saturating_sub(1);
295	                output.push('\n');
296	            }
297	            Event::End(TagEnd::Heading(..)) => {
298	                state.heading_level = None;
299	                output.push_str("\n\n");
300	            }
301	            Event::End(TagEnd::Item) | Event::SoftBreak | Event::HardBreak => {
302	                state.append_raw(output, "\n");
303	            }
304	            Event::Start(Tag::List(first_item)) => {
305	                let kind = match first_item {
306	                    Some(index) => ListKind::Ordered { next_index: index },
307	                    None => ListKind::Unordered,
308	                };
309	                state.list_stack.push(kind);
310	            }
311	            Event::End(TagEnd::List(..)) => {
312	                state.list_stack.pop();
313	                output.push('\n');
314	            }
315	            Event::Start(Tag::Item) => Self::start_item(state, output),
316	            Event::Start(Tag::CodeBlock(kind)) => {
317	                *in_code_block = true;
318	                *code_language = match kind {
319	                    CodeBlockKind::Indented => String::from("text"),
320	                    CodeBlockKind::Fenced(lang) => lang.to_string(),
321	                };
322	                code_buffer.clear();
323	                self.start_code_block(code_language, output);
324	            }
325	            Event::End(TagEnd::CodeBlock) => {
326	                self.finish_code_block(code_buffer, code_language, output);
327	                *in_code_block = false;
328	                code_language.clear();
329	                code_buffer.clear();
330	            }
331	            Event::Start(Tag::Emphasis) => state.emphasis += 1,
332	            Event::End(TagEnd::Emphasis) => state.emphasis = state.emphasis.saturating_sub(1),
333	            Event::Start(Tag::Strong) => state.strong += 1,
334	            Event::End(TagEnd::Strong) => state.strong = state.strong.saturating_sub(1),
335	            Event::Code(code) => {
336	                let rendered =
337	                    format!("{}", format!("`{code}`").with(self.color_theme.inline_code));
338	                state.append_raw(output, &rendered);
339	            }
340	            Event::Rule => output.push_str("---\n"),
341	            Event::Text(text) => {
342	                self.push_text(text.as_ref(), state, output, code_buffer, *in_code_block);
343	            }
344	            Event::Html(html) | Event::InlineHtml(html) => {
345	                state.append_raw(output, &html);
346	            }
347	            Event::FootnoteReference(reference) => {
348	                state.append_raw(output, &format!("[{reference}]"));
349	            }
350	            Event::TaskListMarker(done) => {
351	                state.append_raw(output, if done { "[x] " } else { "[ ] " });
352	            }
353	            Event::InlineMath(math) | Event::DisplayMath(math) => {
354	                state.append_raw(output, &math);
355	            }
356	            Event::Start(Tag::Link { dest_url, .. }) => {
357	                state.link_stack.push(LinkState {
358	                    destination: dest_url.to_string(),
359	                    text: String::new(),
