496	    fn render_table(&self, table: &TableState) -> String {
497	        let mut rows = Vec::new();
498	        if !table.headers.is_empty() {
499	            rows.push(table.headers.clone());
500	        }
501	        rows.extend(table.rows.iter().cloned());
502	
503	        if rows.is_empty() {
504	            return String::new();
505	        }
506	
507	        let column_count = rows.iter().map(Vec::len).max().unwrap_or(0);
508	        let widths = (0..column_count)
509	            .map(|column| {
510	                rows.iter()
511	                    .filter_map(|row| row.get(column))
512	                    .map(|cell| visible_width(cell))
513	                    .max()
514	                    .unwrap_or(0)
515	            })
516	            .collect::<Vec<_>>();
517	
518	        let border = format!("{}", "│".with(self.color_theme.table_border));
519	        let separator = widths
520	            .iter()
521	            .map(|width| "─".repeat(*width + 2))
522	            .collect::<Vec<_>>()
523	            .join(&format!("{}", "┼".with(self.color_theme.table_border)));
524	        let separator = format!("{border}{separator}{border}");
525	
526	        let mut output = String::new();
527	        if !table.headers.is_empty() {
528	            output.push_str(&self.render_table_row(&table.headers, &widths, true));
529	            output.push('\n');
530	            output.push_str(&separator);
531	            if !table.rows.is_empty() {
532	                output.push('\n');
533	            }
534	        }
535	
536	        for (index, row) in table.rows.iter().enumerate() {
537	            output.push_str(&self.render_table_row(row, &widths, false));
538	            if index + 1 < table.rows.len() {
539	                output.push('\n');
540	            }
541	        }
542	
543	        output
544	    }
