546	    fn render_table_row(&self, row: &[String], widths: &[usize], is_header: bool) -> String {
547	        let border = format!("{}", "│".with(self.color_theme.table_border));
548	        let mut line = String::new();
549	        line.push_str(&border);
550	
551	        for (index, width) in widths.iter().enumerate() {
552	            let cell = row.get(index).map_or("", String::as_str);
553	            line.push(' ');
554	            if is_header {
555	                let _ = write!(line, "{}", cell.bold().with(self.color_theme.heading));
556	            } else {
557	                line.push_str(cell);
558	            }
559	            let padding = width.saturating_sub(visible_width(cell));
560	            line.push_str(&" ".repeat(padding + 1));
561	            line.push_str(&border);
562	        }
563	
564	        line
565	    }
