637	fn find_stream_safe_boundary(markdown: &str) -> Option<usize> {
638	    let mut in_fence = false;
639	    let mut last_boundary = None;
640	
641	    for (offset, line) in markdown.split_inclusive('\n').scan(0usize, |cursor, line| {
642	        let start = *cursor;
643	        *cursor += line.len();
644	        Some((start, line))
645	    }) {
646	        let trimmed = line.trim_start();
647	        if trimmed.starts_with("```") || trimmed.starts_with("~~~") {
648	            in_fence = !in_fence;
649	            if !in_fence {
650	                last_boundary = Some(offset + line.len());
651	            }
652	            continue;
653	        }
654	
655	        if in_fence {
656	            continue;
657	        }
658	
659	        if trimmed.is_empty() {
660	            last_boundary = Some(offset + line.len());
661	        }
662	    }
663	
664	    last_boundary
665	}
