671	fn strip_ansi(input: &str) -> String {
672	    let mut output = String::new();
673	    let mut chars = input.chars().peekable();
674	
675	    while let Some(ch) = chars.next() {
676	        if ch == '\u{1b}' {
677	            if chars.peek() == Some(&'[') {
678	                chars.next();
679	                for next in chars.by_ref() {
680	                    if next.is_ascii_alphabetic() {
681	                        break;
682	                    }
683	                }
684	            }
685	        } else {
686	            output.push(ch);
687	        }
688	    }
689	
690	    output
691	}
