130	fn ensure_gitignore_entries(path: &Path) -> Result<InitStatus, std::io::Error> {
131	    if !path.exists() {
132	        let mut lines = vec![GITIGNORE_COMMENT.to_string()];
133	        lines.extend(GITIGNORE_ENTRIES.iter().map(|entry| (*entry).to_string()));
134	        fs::write(path, format!("{}\n", lines.join("\n")))?;
135	        return Ok(InitStatus::Created);
136	    }
137	
138	    let existing = fs::read_to_string(path)?;
139	    let mut lines = existing.lines().map(ToOwned::to_owned).collect::<Vec<_>>();
140	    let mut changed = false;
141	
142	    if !lines.iter().any(|line| line == GITIGNORE_COMMENT) {
143	        lines.push(GITIGNORE_COMMENT.to_string());
144	        changed = true;
145	    }
146	
147	    for entry in GITIGNORE_ENTRIES {
148	        if !lines.iter().any(|line| line == entry) {
149	            lines.push(entry.to_string());
150	            changed = true;
151	        }
152	    }
153	
154	    if !changed {
155	        return Ok(InitStatus::Skipped);
156	    }
157	
158	    fs::write(path, format!("{}\n", lines.join("\n")))?;
159	    Ok(InitStatus::Updated)
160	}
