292	        lines.push("- Run the JavaScript/TypeScript checks from `package.json` before shipping changes (`npm test`, `npm run lint`, `npm run build`, or the repo equivalent).".to_string());
293	    }
294	    if detection.tests_dir && detection.src_dir {
295	        lines.push("- `src/` and `tests/` are both present; update both surfaces together when behavior changes.".to_string());
