240	                model = resolve_model_alias(&flag[8..]).to_string();
241	                index += 1;
242	            }
243	            "--output-format" => {
244	                let value = args
245	                    .get(index + 1)
246	                    .ok_or_else(|| "missing value for --output-format".to_string())?;
247	                output_format = CliOutputFormat::parse(value)?;
248	                index += 2;
249	            }
250	            "--permission-mode" => {
251	                let value = args
252	                    .get(index + 1)
253	                    .ok_or_else(|| "missing value for --permission-mode".to_string())?;
254	                permission_mode_override = Some(parse_permission_mode_arg(value)?);
255	                index += 2;
256	            }
257	            flag if flag.starts_with("--output-format=") => {
258	                output_format = CliOutputFormat::parse(&flag[16..])?;
259	                index += 1;
260	            }
261	            flag if flag.starts_with("--permission-mode=") => {
262	                permission_mode_override = Some(parse_permission_mode_arg(&flag[18..])?);
263	                index += 1;
264	            }
265	            "--dangerously-skip-permissions" => {
266	                permission_mode_override = Some(PermissionMode::DangerFullAccess);
267	                index += 1;
268	            }
269	            "-p" => {
270	                // Claw Code compat: -p "prompt" = one-shot prompt
271	                let prompt = args[index + 1..].join(" ");
