1527	fn run_repl(
1528	    model: String,
1529	    allowed_tools: Option<AllowedToolSet>,
1530	    permission_mode: PermissionMode,
1531	) -> Result<(), Box<dyn std::error::Error>> {
1532	    let mut cli = LiveCli::new(model, true, allowed_tools, permission_mode)?;
1533	    let mut editor =
1534	        input::LineEditor::new("> ", cli.repl_completion_candidates().unwrap_or_default());
1535	    println!("{}", cli.startup_banner());
1536	
1537	    loop {
1538	        editor.set_completions(cli.repl_completion_candidates().unwrap_or_default());
1539	        match editor.read_line()? {
1540	            input::ReadOutcome::Submit(input) => {
1541	                let trimmed = input.trim().to_string();
1542	                if trimmed.is_empty() {
1543	                    continue;
1544	                }
1545	                if matches!(trimmed.as_str(), "/exit" | "/quit") {
1546	                    cli.persist_session()?;
1547	                    break;
1548	                }
1549	                match SlashCommand::parse(&trimmed) {
1550	                    Ok(Some(command)) => {
1551	                        if cli.handle_repl_command(command)? {
1552	                            cli.persist_session()?;
1553	                        }
1554	                        continue;
1555	                    }
1556	                    Ok(None) => {}
1557	                    Err(error) => {
1558	                        eprintln!("{error}");
1559	                        continue;
1560	                    }
1561	                }
1562	                editor.push_history(input);
1563	                cli.run_turn(&trimmed)?;
1564	            }
1565	            input::ReadOutcome::Cancel => {}
1566	            input::ReadOutcome::Exit => {
1567	                cli.persist_session()?;
1568	                break;
1569	            }
1570	        }
1571	    }
1572	
1573	    Ok(())
1574	}
